&lt;h2 id=&#34;Git-图-Git-Graph&#34;&gt;&lt;a href=&#34;#Git-图-Git-Graph&#34; class=&#34;headerlink&#34; title=&#34;Git 图 (Git Graph)&#34;&gt;&lt;/a&gt;Git 图 (Git Graph)&lt;/h2&gt;&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;gitgraph&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    commit id: &amp;quot;初始提交&amp;quot;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    branch develop&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    checkout develop&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    commit id: &amp;quot;添加功能A&amp;quot;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    commit id: &amp;quot;修复bug&amp;quot;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    checkout main&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    merge develop&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    commit id: &amp;quot;发布v1.0&amp;quot;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    branch feature&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    checkout feature&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    commit id: &amp;quot;开发功能B&amp;quot;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    checkout develop&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    commit id: &amp;quot;优化性能&amp;quot;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    checkout feature&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    commit id: &amp;quot;完成功能B&amp;quot;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    checkout develop&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    merge feature&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    checkout main&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    merge develop&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    commit id: &amp;quot;发布v1.1&amp;quot;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;h2 id=&#34;用户旅程图-User-Journey&#34;&gt;&lt;a href=&#34;#用户旅程图-User-Journey&#34; class=&#34;headerlink&#34; title=&#34;用户旅程图 (User Journey)&#34;&gt;&lt;/a&gt;用户旅程图 (User Journey)&lt;/h2&gt;&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;journey&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    title 用户购物体验&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    section 发现产品&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      浏览网站: 5: 用户&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      搜索产品: 3: 用户&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      查看详情: 4: 用户&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    section 购买决策&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      比较价格: 2: 用户&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      查看评价: 4: 用户&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      咨询客服: 3: 用户, 客服&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    section 下单购买&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      加入购物车: 5: 用户&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      填写信息: 3: 用户&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      支付订单: 4: 用户&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    section 售后服务&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      物流跟踪: 4: 用户&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      收货确认: 5: 用户&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;      评价商品: 3: 用户&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;h2 id=&#34;总结&#34;&gt;&lt;a href=&#34;#总结&#34; class=&#34;headerlink&#34; title=&#34;总结&#34;&gt;&lt;/a&gt;总结&lt;/h2&gt;&lt;p&gt;Mermaid 提供了丰富的图表类型：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;流程图&lt;/strong&gt;: 展示业务流程和逻辑关系&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;时序图&lt;/strong&gt;: 描述系统间的交互过程&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;甘特图&lt;/strong&gt;: 项目进度和时间规划&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;类图&lt;/strong&gt;: 面向对象设计的类关系&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;状态图&lt;/strong&gt;: 系统状态转换&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;饼图&lt;/strong&gt;: 数据占比展示&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;Git图&lt;/strong&gt;: 版本控制流程&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;用户旅程图&lt;/strong&gt;: 用户体验流程&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;这些图表让技术文档更加直观易懂！&lt;/p&gt;

 &lt;h1 id=&#34;数学公式展示&#34;&gt;&lt;a href=&#34;#数学公式展示&#34; class=&#34;headerlink&#34; title=&#34;数学公式展示&#34;&gt;&lt;/a&gt;数学公式展示&lt;/h1&gt;&lt;p&gt;本文展示了 KaTeX 数学公式的各种用法。&lt;/p&gt;
&lt;h2 id=&#34;基础公式&#34;&gt;&lt;a href=&#34;#基础公式&#34; class=&#34;headerlink&#34; title=&#34;基础公式&#34;&gt;&lt;/a&gt;基础公式&lt;/h2&gt;&lt;h3 id=&#34;行内公式&#34;&gt;&lt;a href=&#34;#行内公式&#34; class=&#34;headerlink&#34; title=&#34;行内公式&#34;&gt;&lt;/a&gt;行内公式&lt;/h3&gt;&lt;p&gt;这是一个行内公式：$E &amp;#x3D; mc^2$，爱因斯坦的质能方程。&lt;/p&gt;
&lt;p&gt;勾股定理：$a^2 + b^2 &amp;#x3D; c^2$&lt;/p&gt;
&lt;p&gt;二次方程求根公式：$x &amp;#x3D; \frac{-b \pm \sqrt{b^2 - 4ac}}{2a}$&lt;/p&gt;
&lt;h3 id=&#34;块级公式&#34;&gt;&lt;a href=&#34;#块级公式&#34; class=&#34;headerlink&#34; title=&#34;块级公式&#34;&gt;&lt;/a&gt;块级公式&lt;/h3&gt;&lt;p&gt;欧拉公式：&lt;br&gt;$$e^{i\pi} + 1 &amp;#x3D; 0$$&lt;/p&gt;
&lt;p&gt;麦克斯韦方程组：&lt;br&gt;$$&lt;br&gt;\begin{align}&lt;br&gt;\nabla \times \vec{\mathbf{B}} -, \frac1c, \frac{\partial\vec{\mathbf{E}}}{\partial t} &amp;amp;&amp;#x3D; \frac{4\pi}{c}\vec{\mathbf{j}} \&lt;br&gt;\nabla \cdot \vec{\mathbf{E}} &amp;amp;&amp;#x3D; 4 \pi \rho \&lt;br&gt;\nabla \times \vec{\mathbf{E}}, +, \frac1c, \frac{\partial\vec{\mathbf{B}}}{\partial t} &amp;amp;&amp;#x3D; \vec{\mathbf{0}} \&lt;br&gt;\nabla \cdot \vec{\mathbf{B}} &amp;amp;&amp;#x3D; 0&lt;br&gt;\end{align}&lt;br&gt;$$&lt;/p&gt;
&lt;span id=&#34;more&#34;&gt;&lt;/span&gt;

&lt;h2 id=&#34;高级公式&#34;&gt;&lt;a href=&#34;#高级公式&#34; class=&#34;headerlink&#34; title=&#34;高级公式&#34;&gt;&lt;/a&gt;高级公式&lt;/h2&gt;&lt;h3 id=&#34;矩阵&#34;&gt;&lt;a href=&#34;#矩阵&#34; class=&#34;headerlink&#34; title=&#34;矩阵&#34;&gt;&lt;/a&gt;矩阵&lt;/h3&gt;&lt;h1 id=&#34;begin-pmatrix-a-b-c-d-end-pmatrix-begin-pmatrix-x-y-end-pmatrix&#34;&gt;&lt;a href=&#34;#begin-pmatrix-a-b-c-d-end-pmatrix-begin-pmatrix-x-y-end-pmatrix&#34; class=&#34;headerlink&#34; title=&#34;$$\begin{pmatrix}a &amp;amp; b \c &amp;amp; d\end{pmatrix}\begin{pmatrix}x \y\end{pmatrix}&#34;&gt;&lt;/a&gt;$$&lt;br&gt;\begin{pmatrix}&lt;br&gt;a &amp;amp; b \&lt;br&gt;c &amp;amp; d&lt;br&gt;\end{pmatrix}&lt;br&gt;\begin{pmatrix}&lt;br&gt;x \&lt;br&gt;y&lt;br&gt;\end{pmatrix}&lt;/h1&gt;&lt;p&gt;\begin{pmatrix}&lt;br&gt;ax + by \&lt;br&gt;cx + dy&lt;br&gt;\end{pmatrix}&lt;br&gt;$$&lt;/p&gt;
&lt;h3 id=&#34;积分&#34;&gt;&lt;a href=&#34;#积分&#34; class=&#34;headerlink&#34; title=&#34;积分&#34;&gt;&lt;/a&gt;积分&lt;/h3&gt;&lt;p&gt;$$\int_{-\infty}^{\infty} e^{-x^2} dx &amp;#x3D; \sqrt{\pi}$$&lt;/p&gt;
&lt;h3 id=&#34;求和&#34;&gt;&lt;a href=&#34;#求和&#34; class=&#34;headerlink&#34; title=&#34;求和&#34;&gt;&lt;/a&gt;求和&lt;/h3&gt;&lt;p&gt;$$\sum_{n&amp;#x3D;1}^{\infty} \frac{1}{n^2} &amp;#x3D; \frac{\pi^2}{6}$$&lt;/p&gt;
&lt;h3 id=&#34;极限&#34;&gt;&lt;a href=&#34;#极限&#34; class=&#34;headerlink&#34; title=&#34;极限&#34;&gt;&lt;/a&gt;极限&lt;/h3&gt;&lt;p&gt;$$\lim_{x \to 0} \frac{\sin x}{x} &amp;#x3D; 1$$&lt;/p&gt;
&lt;h3 id=&#34;分数&#34;&gt;&lt;a href=&#34;#分数&#34; class=&#34;headerlink&#34; title=&#34;分数&#34;&gt;&lt;/a&gt;分数&lt;/h3&gt;&lt;p&gt;$$\frac{d}{dx}\left( \int_{0}^{x} f(u),du\right)&amp;#x3D;f(x)$$&lt;/p&gt;
&lt;h2 id=&#34;特殊符号&#34;&gt;&lt;a href=&#34;#特殊符号&#34; class=&#34;headerlink&#34; title=&#34;特殊符号&#34;&gt;&lt;/a&gt;特殊符号&lt;/h2&gt;&lt;h3 id=&#34;希腊字母&#34;&gt;&lt;a href=&#34;#希腊字母&#34; class=&#34;headerlink&#34; title=&#34;希腊字母&#34;&gt;&lt;/a&gt;希腊字母&lt;/h3&gt;&lt;p&gt;$\alpha, \beta, \gamma, \delta, \epsilon, \zeta, \eta, \theta$&lt;/p&gt;
&lt;p&gt;$\Alpha, \Beta, \Gamma, \Delta, \Epsilon, \Zeta, \Eta, \Theta$&lt;/p&gt;
&lt;h3 id=&#34;运算符&#34;&gt;&lt;a href=&#34;#运算符&#34; class=&#34;headerlink&#34; title=&#34;运算符&#34;&gt;&lt;/a&gt;运算符&lt;/h3&gt;&lt;p&gt;$\pm, \mp, \times, \div, \cdot, \ast, \star, \circ, \bullet$&lt;/p&gt;
&lt;h3 id=&#34;关系符&#34;&gt;&lt;a href=&#34;#关系符&#34; class=&#34;headerlink&#34; title=&#34;关系符&#34;&gt;&lt;/a&gt;关系符&lt;/h3&gt;&lt;p&gt;$&amp;#x3D;, \neq, &amp;lt;, &amp;gt;, \leq, \geq, \equiv, \approx, \sim, \propto$&lt;/p&gt;
&lt;h3 id=&#34;集合符号&#34;&gt;&lt;a href=&#34;#集合符号&#34; class=&#34;headerlink&#34; title=&#34;集合符号&#34;&gt;&lt;/a&gt;集合符号&lt;/h3&gt;&lt;p&gt;$\in, \notin, \subset, \supset, \subseteq, \supseteq, \cap, \cup, \emptyset$&lt;/p&gt;
&lt;h2 id=&#34;复杂公式示例&#34;&gt;&lt;a href=&#34;#复杂公式示例&#34; class=&#34;headerlink&#34; title=&#34;复杂公式示例&#34;&gt;&lt;/a&gt;复杂公式示例&lt;/h2&gt;&lt;h3 id=&#34;傅里叶变换&#34;&gt;&lt;a href=&#34;#傅里叶变换&#34; class=&#34;headerlink&#34; title=&#34;傅里叶变换&#34;&gt;&lt;/a&gt;傅里叶变换&lt;/h3&gt;&lt;p&gt;$$\mathcal{F}(f)(x) &amp;#x3D; \int_{-\infty}^{\infty} f(t) e^{-2\pi i x t} dt$$&lt;/p&gt;
&lt;h3 id=&#34;薛定谔方程&#34;&gt;&lt;a href=&#34;#薛定谔方程&#34; class=&#34;headerlink&#34; title=&#34;薛定谔方程&#34;&gt;&lt;/a&gt;薛定谔方程&lt;/h3&gt;&lt;p&gt;$$i\hbar\frac{\partial}{\partial t}\Psi(\mathbf{r},t) &amp;#x3D; \hat{H}\Psi(\mathbf{r},t)$$&lt;/p&gt;
&lt;h3 id=&#34;贝叶斯定理&#34;&gt;&lt;a href=&#34;#贝叶斯定理&#34; class=&#34;headerlink&#34; title=&#34;贝叶斯定理&#34;&gt;&lt;/a&gt;贝叶斯定理&lt;/h3&gt;&lt;p&gt;$$P(A|B) &amp;#x3D; \frac{P(B|A)P(A)}{P(B)}$$&lt;/p&gt;
&lt;h3 id=&#34;泰勒级数&#34;&gt;&lt;a href=&#34;#泰勒级数&#34; class=&#34;headerlink&#34; title=&#34;泰勒级数&#34;&gt;&lt;/a&gt;泰勒级数&lt;/h3&gt;&lt;p&gt;$$f(x) &amp;#x3D; \sum_{n&amp;#x3D;0}^{\infty} \frac{f^{(n)}(a)}{n!}(x-a)^n$$&lt;/p&gt;
&lt;h2 id=&#34;化学公式&#34;&gt;&lt;a href=&#34;#化学公式&#34; class=&#34;headerlink&#34; title=&#34;化学公式&#34;&gt;&lt;/a&gt;化学公式&lt;/h2&gt;&lt;p&gt;化学反应方程式：&lt;br&gt;$$\ce{2H2 + O2 -&amp;gt; 2H2O}$$&lt;/p&gt;
&lt;p&gt;分子式：&lt;br&gt;$$\ce{C6H12O6 + 6O2 -&amp;gt; 6CO2 + 6H2O}$$&lt;/p&gt;
&lt;h2 id=&#34;总结&#34;&gt;&lt;a href=&#34;#总结&#34; class=&#34;headerlink&#34; title=&#34;总结&#34;&gt;&lt;/a&gt;总结&lt;/h2&gt;&lt;p&gt;KaTeX 提供了强大的数学公式渲染能力，支持：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;基础数学符号和运算&lt;/li&gt;
&lt;li&gt;复杂的公式排版&lt;/li&gt;
&lt;li&gt;矩阵和向量表示&lt;/li&gt;
&lt;li&gt;积分、求和、极限等高级数学概念&lt;/li&gt;
&lt;li&gt;化学公式支持&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;这使得在博客中展示数学内容变得非常方便！&lt;/p&gt;

 &lt;h1 id=&#34;Shoka-主题功能全面展示&#34;&gt;&lt;a href=&#34;#Shoka-主题功能全面展示&#34; class=&#34;headerlink&#34; title=&#34;Shoka 主题功能全面展示&#34;&gt;&lt;/a&gt;Shoka 主题功能全面展示&lt;/h1&gt;&lt;p&gt;本文展示了 Shoka 主题的各种强大功能。&lt;/p&gt;
&lt;h2 id=&#34;🔗-友链展示&#34;&gt;&lt;a href=&#34;#🔗-友链展示&#34; class=&#34;headerlink&#34; title=&#34;🔗 友链展示&#34;&gt;&lt;/a&gt;🔗 友链展示&lt;/h2&gt;&lt;div class=&#34;links&#34;&gt;&lt;div class=&#34;item&#34; title=&#34;霜月琉璃&#34; style=&#34;--block-color:#e9546b;&#34;&gt;&lt;span class=&#34;exturl image&#34; data-url=&#34;aHR0cHM6Ly9zaG9rYS5sb3N0eXUubWU=&#34; data-background-image=&#34;https://cdn.jsdelivr.net/gh/amehime/shoka@latest/images/avatar.jpg&#34;&gt;&lt;/span&gt;
          &lt;div class=&#34;info&#34;&gt;
          &lt;span class=&#34;exturl title&#34; data-url=&#34;aHR0cHM6Ly9zaG9rYS5sb3N0eXUubWU=&#34;&gt;優萌初華&lt;/span&gt;
          &lt;p class=&#34;desc&#34;&gt;琉璃的医学 &amp; 编程笔记&lt;/p&gt;
          &lt;/div&gt;&lt;/div&gt;&lt;div class=&#34;item&#34; title=&#34;Hexo 官网&#34; style=&#34;--block-color:#0e83cd;&#34;&gt;&lt;span class=&#34;exturl image&#34; data-url=&#34;aHR0cHM6Ly9oZXhvLmlv&#34; data-background-image=&#34;/images/404.png&#34;&gt;&lt;/span&gt;
          &lt;div class=&#34;info&#34;&gt;
          &lt;span class=&#34;exturl title&#34; data-url=&#34;aHR0cHM6Ly9oZXhvLmlv&#34;&gt;Hexo 官网&lt;/span&gt;
          &lt;p class=&#34;desc&#34;&gt;快速、简洁且高效的博客框架&lt;/p&gt;
          &lt;/div&gt;&lt;/div&gt;&lt;/div&gt;

&lt;h2 id=&#34;💻-代码块展示&#34;&gt;&lt;a href=&#34;#💻-代码块展示&#34; class=&#34;headerlink&#34; title=&#34;💻 代码块展示&#34;&gt;&lt;/a&gt;💻 代码块展示&lt;/h2&gt;&lt;figure class=&#34;highlight javascript&#34;&gt;&lt;figcaption&gt;&lt;span&gt;高亮示例&lt;/span&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9kZXZlbG9wZXIubW96aWxsYS5vcmcvemgtQ04vZG9jcy9XZWIvSmF2YVNjcmlwdA==&#34;&gt;参考文档 mark:2,5-7&lt;/span&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;// JavaScript 函数示例&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;function&lt;/span&gt; &lt;span class=&#34;title function_&#34;&gt;greetUser&lt;/span&gt;(&lt;span class=&#34;params&#34;&gt;name&lt;/span&gt;) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt; (!name) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;Hello, Guest!&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;const&lt;/span&gt; greeting = &lt;span class=&#34;string&#34;&gt;`Hello, &lt;span class=&#34;subst&#34;&gt;$&amp;#123;name&amp;#125;&lt;/span&gt;!`&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;variable language_&#34;&gt;console&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;log&lt;/span&gt;(greeting);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; greeting;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;title function_&#34;&gt;greetUser&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;张三&amp;quot;&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;figure class=&#34;highlight bash&#34;&gt;&lt;figcaption&gt;&lt;span&gt;命令行示例 command:(&#34;[root@localhost] $&#34;:1,3||&#34;[user@server] #&#34;:5-6)&lt;/span&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;pwd&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;/home/user/projects&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;built_in&#34;&gt;ls&lt;/span&gt; -la&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;total 16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;drwxr-xr-x 3 user user 4096 Jan  3 14:00 .&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;drwxr-xr-x 5 user user 4096 Jan  3 13:30 ..&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;span id=&#34;more&#34;&gt;&lt;/span&gt;

&lt;h2 id=&#34;🎯-练习题展示&#34;&gt;&lt;a href=&#34;#🎯-练习题展示&#34; class=&#34;headerlink&#34; title=&#34;🎯 练习题展示&#34;&gt;&lt;/a&gt;🎯 练习题展示&lt;/h2&gt;&lt;ol&gt;
&lt;li&gt;&lt;p&gt;Hexo 是一个基于 Node.js 的静态博客框架。 {.quiz .true}&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;下列哪些是 Shoka 主题的特色功能？ {.quiz .multi}&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;友链展示 {.correct}&lt;/li&gt;
&lt;li&gt;代码高亮 {.correct}&lt;/li&gt;
&lt;li&gt;数学公式支持 {.correct}&lt;/li&gt;
&lt;li&gt;视频播放&lt;br&gt;{.options}&lt;blockquote&gt;
&lt;ul&gt;
&lt;li&gt;✅ 支持友链卡片展示&lt;/li&gt;
&lt;li&gt;✅ 支持多种代码高亮&lt;/li&gt;
&lt;li&gt;✅ 支持 KaTeX 数学公式&lt;/li&gt;
&lt;li&gt;❌ 不是主要特色功能&lt;br&gt;{.options}&lt;/li&gt;
&lt;/ul&gt;
&lt;/blockquote&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;Shoka 主题基于 [Hexo]{.gap} 框架开发。 {.quiz .fill}&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h2 id=&#34;🎨-文字特效展示&#34;&gt;&lt;a href=&#34;#🎨-文字特效展示&#34; class=&#34;headerlink&#34; title=&#34;🎨 文字特效展示&#34;&gt;&lt;/a&gt;🎨 文字特效展示&lt;/h2&gt;&lt;p&gt;++ 下划线效果 ++&lt;br&gt;++ 波浪线效果 ++{.wavy}&lt;br&gt;++ 着重点效果 ++{.dot}&lt;br&gt;++ 彩色下划线 ++{.primary}&lt;br&gt;~~ 删除线效果 ~~&lt;br&gt;&amp;#x3D;&amp;#x3D; 荧光高亮效果 &amp;#x3D;&amp;#x3D;&lt;/p&gt;
&lt;p&gt;[赤橙黄绿青蓝紫]{.rainbow}&lt;br&gt;[红色文字]{.red} [蓝色文字]{.blue} [绿色文字]{.green}&lt;/p&gt;
&lt;p&gt;快捷键示例：[Ctrl]{.kbd} + [C]{.kbd .primary}&lt;/p&gt;
&lt;h2 id=&#34;🔒-隐藏文字展示&#34;&gt;&lt;a href=&#34;#🔒-隐藏文字展示&#34; class=&#34;headerlink&#34; title=&#34;🔒 隐藏文字展示&#34;&gt;&lt;/a&gt;🔒 隐藏文字展示&lt;/h2&gt;&lt;p&gt;!! 这是隐藏的内容，鼠标悬停显示 !!&lt;br&gt;!! 这是模糊的内容，选中文字显示 !!{.blur}&lt;/p&gt;
&lt;h2 id=&#34;🏷️-标签展示&#34;&gt;&lt;a href=&#34;#🏷️-标签展示&#34; class=&#34;headerlink&#34; title=&#34;🏷️ 标签展示&#34;&gt;&lt;/a&gt;🏷️ 标签展示&lt;/h2&gt;&lt;p&gt;[默认]{.label} [主要]{.label .primary} [信息]{.label .info}&lt;br&gt;[成功]{.label .success} [警告]{.label .warning} [危险]{.label .danger}&lt;/p&gt;
&lt;h2 id=&#34;📝-提醒块展示&#34;&gt;&lt;a href=&#34;#📝-提醒块展示&#34; class=&#34;headerlink&#34; title=&#34;📝 提醒块展示&#34;&gt;&lt;/a&gt;📝 提醒块展示&lt;/h2&gt;&lt;p&gt;:::info 信息提示&lt;br&gt;这是一个信息提示块，用于显示重要信息。&lt;br&gt;:::&lt;/p&gt;
&lt;p&gt;:::success 成功提示&lt;br&gt;这是一个成功提示块，表示操作成功完成。&lt;br&gt;:::&lt;/p&gt;
&lt;p&gt;:::warning 警告提示&lt;br&gt;这是一个警告提示块，提醒用户注意。&lt;br&gt;:::&lt;/p&gt;
&lt;p&gt;:::danger 危险提示&lt;br&gt;这是一个危险提示块，警告用户潜在风险。&lt;br&gt;:::&lt;/p&gt;
&lt;h2 id=&#34;📑-标签卡展示&#34;&gt;&lt;a href=&#34;#📑-标签卡展示&#34; class=&#34;headerlink&#34; title=&#34;📑 标签卡展示&#34;&gt;&lt;/a&gt;📑 标签卡展示&lt;/h2&gt;&lt;p&gt;;;;demo1 前端技术&lt;/p&gt;
&lt;h3 id=&#34;HTML&#34;&gt;&lt;a href=&#34;#HTML&#34; class=&#34;headerlink&#34; title=&#34;HTML&#34;&gt;&lt;/a&gt;HTML&lt;/h3&gt;&lt;p&gt;超文本标记语言，用于创建网页结构。&lt;/p&gt;
&lt;h3 id=&#34;CSS&#34;&gt;&lt;a href=&#34;#CSS&#34; class=&#34;headerlink&#34; title=&#34;CSS&#34;&gt;&lt;/a&gt;CSS&lt;/h3&gt;&lt;p&gt;层叠样式表，用于网页样式设计。&lt;br&gt;;;;&lt;/p&gt;
&lt;p&gt;;;;demo1 后端技术&lt;/p&gt;
&lt;h3 id=&#34;Node-js&#34;&gt;&lt;a href=&#34;#Node-js&#34; class=&#34;headerlink&#34; title=&#34;Node.js&#34;&gt;&lt;/a&gt;Node.js&lt;/h3&gt;&lt;p&gt;基于 Chrome V8 引擎的 JavaScript 运行环境。&lt;/p&gt;
&lt;h3 id=&#34;Python&#34;&gt;&lt;a href=&#34;#Python&#34; class=&#34;headerlink&#34; title=&#34;Python&#34;&gt;&lt;/a&gt;Python&lt;/h3&gt;&lt;p&gt;简洁优雅的编程语言，适合快速开发。&lt;br&gt;;;;&lt;/p&gt;
&lt;h2 id=&#34;📁-折叠块展示&#34;&gt;&lt;a href=&#34;#📁-折叠块展示&#34; class=&#34;headerlink&#34; title=&#34;📁 折叠块展示&#34;&gt;&lt;/a&gt;📁 折叠块展示&lt;/h2&gt;&lt;p&gt;+++ primary JavaScript 基础知识&lt;br&gt;JavaScript 是一种高级的、解释型的编程语言。&lt;/p&gt;
&lt;figure class=&#34;highlight javascript&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;const&lt;/span&gt; message = &lt;span class=&#34;string&#34;&gt;&amp;quot;Hello, World!&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;variable language_&#34;&gt;console&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;log&lt;/span&gt;(message);&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;p&gt;+++&lt;/p&gt;
&lt;p&gt;+++ success CSS 样式技巧&lt;br&gt;CSS 可以让网页变得更加美观。&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;使用 Flexbox 布局&lt;/li&gt;
&lt;li&gt;响应式设计&lt;/li&gt;
&lt;li&gt;动画效果&lt;br&gt;+++&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;✅-待办事项展示&#34;&gt;&lt;a href=&#34;#✅-待办事项展示&#34; class=&#34;headerlink&#34; title=&#34;✅ 待办事项展示&#34;&gt;&lt;/a&gt;✅ 待办事项展示&lt;/h2&gt;&lt;ul&gt;
&lt;li&gt;&lt;input checked=&#34;&#34; disabled=&#34;&#34; type=&#34;checkbox&#34;&gt; 学习 Hexo 基础&lt;/li&gt;
&lt;li&gt;&lt;input checked=&#34;&#34; disabled=&#34;&#34; type=&#34;checkbox&#34;&gt; 安装 Shoka 主题 {.success}&lt;/li&gt;
&lt;li&gt;&lt;input disabled=&#34;&#34; type=&#34;checkbox&#34;&gt; 配置主题功能&lt;/li&gt;
&lt;li&gt;&lt;input disabled=&#34;&#34; type=&#34;checkbox&#34;&gt; 编写第一篇文章 {.primary}&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;🔤-注音展示&#34;&gt;&lt;a href=&#34;#🔤-注音展示&#34; class=&#34;headerlink&#34; title=&#34;🔤 注音展示&#34;&gt;&lt;/a&gt;🔤 注音展示&lt;/h2&gt;&lt;p&gt;{可愛い犬^か・わい・いいぬ}&lt;br&gt;{Hello^你好}&lt;br&gt;{Hexo^静态博客框架}&lt;/p&gt;
&lt;h2 id=&#34;🧮-数学公式展示&#34;&gt;&lt;a href=&#34;#🧮-数学公式展示&#34; class=&#34;headerlink&#34; title=&#34;🧮 数学公式展示&#34;&gt;&lt;/a&gt;🧮 数学公式展示&lt;/h2&gt;&lt;p&gt;行内公式：$E &amp;#x3D; mc^2$&lt;/p&gt;
&lt;p&gt;块级公式：&lt;br&gt;$$&lt;br&gt;\begin{align}&lt;br&gt;\nabla \times \vec{\mathbf{B}} -, \frac1c, \frac{\partial\vec{\mathbf{E}}}{\partial t} &amp;amp;&amp;#x3D; \frac{4\pi}{c}\vec{\mathbf{j}} \&lt;br&gt;\nabla \cdot \vec{\mathbf{E}} &amp;amp;&amp;#x3D; 4 \pi \rho \&lt;br&gt;\nabla \times \vec{\mathbf{E}}, +, \frac1c, \frac{\partial\vec{\mathbf{B}}}{\partial t} &amp;amp;&amp;#x3D; \vec{\mathbf{0}} \&lt;br&gt;\nabla \cdot \vec{\mathbf{B}} &amp;amp;&amp;#x3D; 0&lt;br&gt;\end{align}&lt;br&gt;$$&lt;/p&gt;
&lt;h2 id=&#34;📊-流程图展示&#34;&gt;&lt;a href=&#34;#📊-流程图展示&#34; class=&#34;headerlink&#34; title=&#34;📊 流程图展示&#34;&gt;&lt;/a&gt;📊 流程图展示&lt;/h2&gt;&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;graph TD&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    A[开始] --&amp;gt; B&amp;#123;是否安装 Hexo?&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    B --&amp;gt;|是| C[安装 Shoka 主题]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    B --&amp;gt;|否| D[安装 Hexo]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    D --&amp;gt; C&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    C --&amp;gt; E[配置主题]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    E --&amp;gt; F[编写文章]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    F --&amp;gt; G[部署博客]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    G --&amp;gt; H[完成]&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;sequenceDiagram&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    participant 用户&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    participant Hexo&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    participant Shoka&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    用户-&amp;gt;&amp;gt;Hexo: 创建新文章&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    Hexo-&amp;gt;&amp;gt;Shoka: 应用主题样式&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    Shoka-&amp;gt;&amp;gt;用户: 渲染页面&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    用户-&amp;gt;&amp;gt;Shoka: 查看效果&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;h2 id=&#34;😀-Emoji-展示&#34;&gt;&lt;a href=&#34;#😀-Emoji-展示&#34; class=&#34;headerlink&#34; title=&#34;😀 Emoji 展示&#34;&gt;&lt;/a&gt;😀 Emoji 展示&lt;/h2&gt;&lt;p&gt;:heart: :star: :rocket: :computer: :books: :coffee:&lt;/p&gt;
&lt;h2 id=&#34;总结&#34;&gt;&lt;a href=&#34;#总结&#34; class=&#34;headerlink&#34; title=&#34;总结&#34;&gt;&lt;/a&gt;总结&lt;/h2&gt;&lt;p&gt;Shoka 主题提供了丰富的功能，让博客内容更加生动有趣！&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;支持多种内容展示方式&lt;/li&gt;
&lt;li&gt;提供丰富的交互功能&lt;/li&gt;
&lt;li&gt;具有优秀的视觉效果&lt;/li&gt;
&lt;li&gt;易于使用和配置&lt;/li&gt;
&lt;/ul&gt;

 &lt;h1 id=&#34;JavaScript-基础知识总结&#34;&gt;&lt;a href=&#34;#JavaScript-基础知识总结&#34; class=&#34;headerlink&#34; title=&#34;JavaScript 基础知识总结&#34;&gt;&lt;/a&gt;JavaScript 基础知识总结&lt;/h1&gt;&lt;p&gt;本文总结了 JavaScript 的基础知识点。&lt;/p&gt;
&lt;h2 id=&#34;变量声明&#34;&gt;&lt;a href=&#34;#变量声明&#34; class=&#34;headerlink&#34; title=&#34;变量声明&#34;&gt;&lt;/a&gt;变量声明&lt;/h2&gt;&lt;p&gt;JavaScript 中有三种声明变量的方式：&lt;/p&gt;
&lt;h3 id=&#34;var&#34;&gt;&lt;a href=&#34;#var&#34; class=&#34;headerlink&#34; title=&#34;var&#34;&gt;&lt;/a&gt;var&lt;/h3&gt;&lt;figure class=&#34;highlight javascript&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;var&lt;/span&gt; name = &lt;span class=&#34;string&#34;&gt;&amp;quot;张三&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;variable language_&#34;&gt;console&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;log&lt;/span&gt;(name); &lt;span class=&#34;comment&#34;&gt;// 张三&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;h3 id=&#34;let&#34;&gt;&lt;a href=&#34;#let&#34; class=&#34;headerlink&#34; title=&#34;let&#34;&gt;&lt;/a&gt;let&lt;/h3&gt;&lt;figure class=&#34;highlight javascript&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;let&lt;/span&gt; age = &lt;span class=&#34;number&#34;&gt;25&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;variable language_&#34;&gt;console&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;log&lt;/span&gt;(age); &lt;span class=&#34;comment&#34;&gt;// 25&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;h3 id=&#34;const&#34;&gt;&lt;a href=&#34;#const&#34; class=&#34;headerlink&#34; title=&#34;const&#34;&gt;&lt;/a&gt;const&lt;/h3&gt;&lt;figure class=&#34;highlight javascript&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;const&lt;/span&gt; &lt;span class=&#34;variable constant_&#34;&gt;PI&lt;/span&gt; = &lt;span class=&#34;number&#34;&gt;3.14159&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;variable language_&#34;&gt;console&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;log&lt;/span&gt;(&lt;span class=&#34;variable constant_&#34;&gt;PI&lt;/span&gt;); &lt;span class=&#34;comment&#34;&gt;// 3.14159&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;span id=&#34;more&#34;&gt;&lt;/span&gt;

&lt;h2 id=&#34;数据类型&#34;&gt;&lt;a href=&#34;#数据类型&#34; class=&#34;headerlink&#34; title=&#34;数据类型&#34;&gt;&lt;/a&gt;数据类型&lt;/h2&gt;&lt;p&gt;JavaScript 有以下几种基本数据类型：&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;&lt;strong&gt;Number&lt;/strong&gt; - 数字&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;String&lt;/strong&gt; - 字符串  &lt;/li&gt;
&lt;li&gt;&lt;strong&gt;Boolean&lt;/strong&gt; - 布尔值&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;Undefined&lt;/strong&gt; - 未定义&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;Null&lt;/strong&gt; - 空值&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;Symbol&lt;/strong&gt; - 符号（ES6新增）&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;BigInt&lt;/strong&gt; - 大整数（ES2020新增）&lt;/li&gt;
&lt;/ol&gt;
&lt;h2 id=&#34;函数&#34;&gt;&lt;a href=&#34;#函数&#34; class=&#34;headerlink&#34; title=&#34;函数&#34;&gt;&lt;/a&gt;函数&lt;/h2&gt;&lt;h3 id=&#34;函数声明&#34;&gt;&lt;a href=&#34;#函数声明&#34; class=&#34;headerlink&#34; title=&#34;函数声明&#34;&gt;&lt;/a&gt;函数声明&lt;/h3&gt;&lt;figure class=&#34;highlight javascript&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;function&lt;/span&gt; &lt;span class=&#34;title function_&#34;&gt;greet&lt;/span&gt;(&lt;span class=&#34;params&#34;&gt;name&lt;/span&gt;) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;&amp;quot;Hello, &amp;quot;&lt;/span&gt; + name + &lt;span class=&#34;string&#34;&gt;&amp;quot;!&amp;quot;&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;h3 id=&#34;箭头函数&#34;&gt;&lt;a href=&#34;#箭头函数&#34; class=&#34;headerlink&#34; title=&#34;箭头函数&#34;&gt;&lt;/a&gt;箭头函数&lt;/h3&gt;&lt;figure class=&#34;highlight javascript&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;const&lt;/span&gt; &lt;span class=&#34;title function_&#34;&gt;greet&lt;/span&gt; = (&lt;span class=&#34;params&#34;&gt;name&lt;/span&gt;) =&amp;gt; &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; &lt;span class=&#34;string&#34;&gt;`Hello, &lt;span class=&#34;subst&#34;&gt;$&amp;#123;name&amp;#125;&lt;/span&gt;!`&lt;/span&gt;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;h2 id=&#34;总结&#34;&gt;&lt;a href=&#34;#总结&#34; class=&#34;headerlink&#34; title=&#34;总结&#34;&gt;&lt;/a&gt;总结&lt;/h2&gt;&lt;p&gt;JavaScript 是一门功能强大的编程语言，掌握好基础知识对后续学习很重要。&lt;/p&gt;

 &lt;h1 id=&#34;欢迎来到我的技术博客！&#34;&gt;&lt;a href=&#34;#欢迎来到我的技术博客！&#34; class=&#34;headerlink&#34; title=&#34;欢迎来到我的技术博客！&#34;&gt;&lt;/a&gt;欢迎来到我的技术博客！&lt;/h1&gt;&lt;p&gt;这是一篇置顶文章，用来欢迎访问者。&lt;/p&gt;
